query Community($skip: Int, $orderBy: OrderByInput, $where: CommunityWhereInput, $limit: Int) {
  community(skip: $skip, orderBy: $orderBy, where: $where, limit: $limit) {
    total
    data {
      id
      isRead
      catalog {
        id
        title
      }
      title
      subImages
      description
      files
      videos
      isPublic
      createdAt
      updatedAt
      image
    }
  }
}

