query ItemsV2($where: ItemV2WhereInput, $skip: Int, $noLimit: Boolean, $limit: Int, $orderBy: OrderByItem) {
  itemsV2(
    where: $where
    skip: $skip
    noLimit: $noLimit
    limit: $limit
    orderBy: $orderBy
  ) {
    total
    data {
      _id
      trackingId
      itemName
      itemValueKIP
      itemValueTHB
      itemValueUSD
      realItemValueKIP
      realItemValueTHB
      realItemValueUSD
      receiverName
      receiverPhone
      description
      trackingPlatform
      isSummary
      destSendDate
      charge_on_shop
      itemStatus
      contactStatus
      originSendDate
      receiveBackwardDate
      width
      weight
      isCod
      isExtraItem
      packagePrice
      isDeposit
      originReceiveDate
      destReceiveDate
      sendCompleteDate
      isCustomerCreated
      isBackward
      billNumber
      providedBy {
        _id
      }
      originProvinceId {
        provinceName
      }
      destProvinceId {
        provinceName
      }
      originBranchId {
        branch_name
      }
      destBranchId {
        branch_name
        branch_address
        districtName
        contactInfo
      }
      customerId {
        id_list
        full_name
        contact_info
      }
      createdBy {
        first_name
        phone_number
      }
      originReceiveBy {
        first_name
        phone_number
      }
      original_shipper {
        _id
        full_name
      }
      destination_shipper {
        _id
        full_name
      }
    }
  }
}
